#include <stdio.h>
#include <string.h>
int minUgliness(char *S1, char *S2) {
    int minUgliness = 1000000000;
    for (int i = 0; i < strlen(S1); i++) {
        for (int j = 0; j < strlen(S2); j++) {
            if (S1[i] == S2[j]) {
                int petal1 = i + 1;
                int petal2 = strlen(S1) - i;
                int petal3 = j + 1;
                int petal4 = strlen(S2) - j;
                int ugliness = abs(petal1 - petal2) + abs(petal2 - petal3) + abs(petal3 - petal4) + abs(petal4 - petal1);
                minUgliness = (ugliness < minUgliness) ? ugliness : minUgliness;
            }
        }
    }
    return minUgliness;
}
int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        char S1[100005], S2[100005];
        scanf("%s %s", S1, S2);
        printf("%d\n", minUgliness(S1, S2));
    }
    return 0;
}

