import java.util.Scanner;
public class Main {
    public static int minUgliness(String S1, String S2) {
        int minUgliness = 1000000000;
        for (int i = 0; i < S1.length(); i++) {
            for (int j = 0; j < S2.length(); j++) {
                if (S1.charAt(i) == S2.charAt(j)) {
                    int petal1 = i + 1;
                    int petal2 = S1.length() - i;
                    int petal3 = j + 1;
                    int petal4 = S2.length() - j;
                    int ugliness = Math.abs(petal1 - petal2) + Math.abs(petal2 - petal3) + Math.abs(petal3 - petal4) + Math.abs(petal4 - petal1);
                    minUgliness = (ugliness < minUgliness) ? ugliness : minUgliness;
                }
            }
        }
        return minUgliness;
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        scanner.nextLine();
        for (int t = 0; t < T; t++) {
            String S1 = scanner.nextLine();
            String S2 = scanner.nextLine();
            System.out.println(minUgliness(S1, S2));
        }
    }
}

